// ============================================================
// SOAR-002 — Code_Triage_Incident
// VERSION CORRIGÉE FINALE — headers token fix
// ============================================================

const SOC_TOKEN = String($vars.SOAR_BF_TOKEN || '').trim();
if (!SOC_TOKEN) {
  return [{ json: { error: 'MISCONFIGURATION',
    message: 'SOAR_BF_TOKEN manquant en configuration n8n' } }];
}

const raw   = $input.first().json;
const input = raw.body || raw;
const now   = new Date().toISOString();

// ── TOKEN — lecture headers HTTP EN PRIORITÉ ──────────────
const receivedToken = String(
  (raw.headers && raw.headers['x-soc-token']) ||
  (raw.headers && raw.headers['X-Soc-Token']) ||
  raw['x-soc-token']   ||
  raw.soc_token        ||
  input['x-soc-token'] ||
  input.soc_token      || ''
).trim();

if (!receivedToken) {
  return [{ json: { error: 'UNAUTHORIZED',
    message: 'Token manquant', timestamp: now } }];
}
if (receivedToken !== SOC_TOKEN) {
  console.log('[SECURITY][SOAR-002] WARN: Token invalide — ' + now);
  return [{ json: { error: 'UNAUTHORIZED',
    message: 'Token SOC invalide — SOAR-002', timestamp: now } }];
}

function sanitizeForLog(val) {
  return String(val).replace(/[|\n\r\t]/g, '_').substring(0, 100);
}
function normalizeIP(raw_ip) {
  const s = String(raw_ip || '').trim().toLowerCase();
  if (s.startsWith('::ffff:')) return s.slice(7);
  if (/^(\d{1,3}\.){3}\d{1,3}$/.test(s)) {
    const octets = s.split('.').map(Number);
    if (octets.some(o => isNaN(o) || o < 0 || o > 255)) return null;
    return octets.join('.');
  }
  if (/^[0-9a-f:]{3,39}$/.test(s)) return s;
  return null;
}

const rawIP    = input.source_ip || input.ip || '';
const sourceIP = normalizeIP(rawIP);
if (!sourceIP) {
  return [{ json: { error: 'INVALID_IP',
    message: 'Format IP invalide: ' + sanitizeForLog(rawIP),
    timestamp: now } }];
}

const PROTECTED_IPS = ['0.0.0.0','127.0.0.1','::1','10.0.0.1','localhost'];
if (PROTECTED_IPS.includes(sourceIP)) {
  return [{ json: { error: 'PROTECTED_IP',
    message: 'Triage refusé — IP protégée: ' + sourceIP,
    timestamp: now } }];
}

const incId    = sanitizeForLog(input.incident_id || 'INC-BF-' + Date.now());
const username = sanitizeForLog(input.username || input.user || 'unknown');

const incident = {
  incident_id   : incId,
  incident_type : 'brute_force',
  source_ip     : sourceIP,
  username,
  mitre_tech    : sanitizeForLog(input.mitre_tech    || 'T1110'),
  mitre_name    : sanitizeForLog(input.mitre_name    || 'Brute Force'),
  mitre_tactic  : sanitizeForLog(input.mitre_tactic  || 'Credential Access'),
  severity      : sanitizeForLog(input.severity      || 'HIGH'),
  severity_score: Number(input.severity_score || 75),
  priority      : sanitizeForLog(input.priority      || 'P1'),
  sla_due       : sanitizeForLog(input.sla_due       || now),
  sla_minutes   : Number(input.sla_minutes           || 60),
  etat_siem     : sanitizeForLog(input.etat_siem     || 'q3'),
  etat_soar     : 'q1_Triage',
  timestamp     : sanitizeForLog(input.timestamp     || now),
  status        : 'TRIAGE',
  created_at    : now,
  audit_trail   : [
    now + ' | TRIAGE | SOC_AUTO | Alerte reçue — IP: ' +
    sanitizeForLog(sourceIP) + ' — Priority: ' +
    sanitizeForLog(input.priority || 'P1')
  ]
};

const store = $getWorkflowStaticData('global');
store['LAST_INCIDENT'] = incId;
store[incId]           = JSON.stringify(incident);

return [{ json: incident }];

// ============================================================
// SOAR-002 — Code_Traitement_Decision
// ============================================================

var raw    = $input.first().json;
var body   = raw.body || raw;
var nowISO = new Date().toISOString();

// ── PARSE DÉCISION + OTP ──────────────────────────────────
var bodyRaw = String(
  body.Body || body.body || raw.Body || body.decision || ''
).toUpperCase().trim();

const OTP_PATTERN = /^(BF)-(OUI|NON)-(\d{6})$/;
const match = bodyRaw.match(OTP_PATTERN);

if (!match) {
  console.log('[SOAR-002] Format invalide: ' + bodyRaw);
  return [{ json: {
    status : 'IGNORED',
    message: 'Format attendu: BF-OUI-123456 ou BF-NON-123456',
    received: bodyRaw, timestamp: nowISO
  }}];
}

const [, , decision, otpCode] = match;

// ── VALIDATION EXPÉDITEUR ──────────────────────────────────
var sender = String(
  body.From || body.from || raw.From || raw.from || ''
).replace('whatsapp:', '').trim();

if (!sender) {
  return [{ json: { error: 'MISSING_SENDER',
    message: 'Expéditeur non identifié', timestamp: nowISO } }];
}

var AUTHORIZED_PHONES = [];
if ($vars.ANALYST_L1_PHONE)
  AUTHORIZED_PHONES.push(String($vars.ANALYST_L1_PHONE).trim());
if ($vars.ANALYST_L2_PHONE)
  AUTHORIZED_PHONES.push(String($vars.ANALYST_L2_PHONE).trim());

if (AUTHORIZED_PHONES.length === 0) {
  return [{ json: { error: 'MISCONFIGURATION',
    message: 'ANALYST_L1_PHONE / ANALYST_L2_PHONE non configurés' } }];
}
if (!AUTHORIZED_PHONES.includes(sender)) {
  console.log('[SECURITY][SOAR-002] Expéditeur non autorisé: ' + sender);
  return [{ json: { error: 'UNAUTHORIZED',
    message: 'Expéditeur non autorisé', timestamp: nowISO } }];
}

var ANALYST_NAMES = {};
if ($vars.ANALYST_L1_PHONE)
  ANALYST_NAMES[String($vars.ANALYST_L1_PHONE).trim()] = 'SOC_L1_Analyst';
if ($vars.ANALYST_L2_PHONE)
  ANALYST_NAMES[String($vars.ANALYST_L2_PHONE).trim()] = 'SOC_L2_Lead';
var analystName = ANALYST_NAMES[sender] || 'SOC_L1_Analyst';

// ── VALIDATION OTP DEPUIS SUPABASE ────────────────────────
var otpRow = null;
try {
  const dbResult = $('DB_ValidateOTP').first()?.json;
  if (dbResult && dbResult.otp_code) {
    otpRow = dbResult;
  }
} catch(e) {
  console.log('[SOAR-002] Impossible de lire DB_ValidateOTP: ' + e.message);
}

if (!otpRow) {
  console.log('[SECURITY][SOAR-002] OTP invalide ou expiré: ' + otpCode.substring(0,3) + '***');
  return [{ json: {
    error    : 'INVALID_OTP',
    message  : 'OTP invalide, expiré, ou déjà utilisé',
    timestamp: nowISO
  }}];
}

const incidentId = otpRow.incident_id;

// ── LECTURE INCIDENT DEPUIS STORE (avec fallback DB) ──────
var store = $getWorkflowStaticData('global');
var incidentData = {};
try { incidentData = JSON.parse(store[incidentId] || '{}'); }
catch(e) { incidentData = {}; }

// FALLBACK : si le store est vide (restart n8n entre alerte et réponse),
// on reconstruit les données minimales depuis l'OTP row et les données
// disponibles dans le contexte courant
if (!incidentData.incident_id) {
  console.log('[SOAR-002][WARN] Store vide pour: ' + incidentId +
    ' — reconstruction depuis contexte OTP');
  incidentData = {
    incident_id   : incidentId,
    source_ip     : String(body.source_ip || raw.source_ip || '0.0.0.0'),
    username      : String(body.username || raw.username || 'unknown'),
    mitre_tech    : String(body.mitre_tech || raw.mitre_tech || 'T1110'),
    mitre_name    : String(body.mitre_name || raw.mitre_name || 'Brute Force'),
    mitre_tactic  : String(body.mitre_tactic || raw.mitre_tactic || 'Credential Access'),
    severity      : String(body.severity || raw.severity || 'HIGH'),
    severity_score: Number(body.severity_score || raw.severity_score || 75),
    priority      : String(body.priority || raw.priority || 'P1'),
    sla_minutes   : Number(body.sla_minutes || raw.sla_minutes || 60),
    audit_trail   : [],
    created_at    : new Date(Date.now() - 300000).toISOString()
  };
}

function sanitizeForLog(val) {
  return String(val).replace(/[|\n\r\t]/g, '_').substring(0, 100);
}

var trail = Array.isArray(incidentData.audit_trail)
  ? incidentData.audit_trail : [];
trail.push(
  nowISO + ' | DECISION | ' + sanitizeForLog(analystName) +
  ' | Réponse: ' + sanitizeForLog(decision) +
  ' | OTP: ' + otpCode.substring(0, 3) + '***' +
  ' | IP: ' + sanitizeForLog(incidentData.source_ip)
);

delete store['LAST_INCIDENT'];

return [{ json: {
  incident_id   : incidentData.incident_id,
  source_ip     : incidentData.source_ip,
  username      : incidentData.username,
  mitre_tech    : incidentData.mitre_tech,
  mitre_name    : incidentData.mitre_name,
  mitre_tactic  : incidentData.mitre_tactic,
  severity      : incidentData.severity,
  severity_score: incidentData.severity_score,
  priority      : incidentData.priority,
  sla_minutes   : incidentData.sla_minutes,
  decided_by    : analystName,
  decided_at    : nowISO,
  decision,
  otp_code      : otpCode,
  is_approved   : (decision === 'OUI'),
  audit_trail   : trail
}}];

// ============================================================
// SOAR-002 — Containment approuvé
// ============================================================
var input  = $input.first().json;
var now    = new Date().toISOString();
var trail  = Array.isArray(input.audit_trail) ? input.audit_trail : [];
trail.push(now + ' | CONTAINMENT | ' + (input.decided_by || 'SOC_AUTO') +
           ' | Blocage IP autorisé — IP: ' + (input.source_ip || 'unknown'));

var store = $getWorkflowStaticData('global');
var key   = input.incident_id;

if (key) {
  // Sauvegarder l'incident_id pour que Code_Cloture_Incident puisse le retrouver
  // même après que SIM-004 ait écrasé le contexte $json
  store['_last_contained_id'] = key;

  if (store[key]) {
    try {
      var stored        = JSON.parse(store[key]);
      stored.status     = 'CONTAINED';
      stored.etat_soar  = 'q4_Containment';
      stored.decided_by = input.decided_by;
      stored.decided_at = now;
      store[key]        = JSON.stringify(stored);
    } catch(e) {
      console.log('[SOAR-002] WARN: Impossible de mettre à jour le store pour ' + key);
    }
  }
}

return [{ json: Object.assign({}, input, {
  status     : 'CONTAINED',
  etat_soar  : 'q4_Containment',
  decided_at : now,
  audit_trail: trail
}) }];

// ============================================================
// SOAR-002 — Code_Cloture_Incident
// VERSION SUPABASE — plus de métriques dans StaticData
// ============================================================

var simResponse = $input.first().json;
var now         = new Date().toISOString();
var rule_id     = simResponse.rule_id || 'RULE_UNKNOWN';

if (simResponse.status !== 'SUCCESS') {
  console.log('[SOAR-002] WARN: SIM-004 retourne échec: ' + (simResponse.message || 'unknown'));
  return [{ json: {
    error       : 'CONTAINMENT_FAILED',
    message     : 'Simulateur erreur: ' + (simResponse.message || 'unknown'),
    sim_response: simResponse,
    timestamp   : now
  }}];
}

var store = $getWorkflowStaticData('global');

var incidentId = simResponse.incident_id;
if (!incidentId || incidentId === 'INC-UNKNOWN') {
  incidentId = store['_last_contained_id'] || null;
}

var incidentData = {};
if (incidentId && store[incidentId]) {
  try {
    incidentData = JSON.parse(store[incidentId]);
  } catch(e) { incidentData = {}; }
}

// Fallback si incident non trouvé en store (vient de Supabase via ORCH-000)
if (!incidentData.incident_id) {
  console.log('[SOAR-002] Store miss pour: ' + incidentId + ' — utilisation données SIM');
  incidentData = {
    incident_id   : incidentId  || 'INC-UNKNOWN-' + Date.now(),
    source_ip     : simResponse.ip_blocked || '0.0.0.0',
    username      : 'unknown',
    mitre_tech    : 'T1110',
    mitre_name    : 'Brute Force',
    mitre_tactic  : 'Credential Access',
    severity      : 'HIGH',
    severity_score: 75,
    priority      : 'P1',
    decided_by    : 'SOC_L1_Analyst',
    audit_trail   : [],
    created_at    : new Date(Date.now() - 60000).toISOString()
  };
}

var trail = Array.isArray(incidentData.audit_trail) ? incidentData.audit_trail : [];
trail.push(now + ' | CLOSED | SOC_AUTO | IP bloquée — Firewall: PaloAlto-NGFW-01 — Rule: ' + rule_id);

// Calcul MTTR pour retourner au node Postgres
var mttr_minutes = 0;
if (incidentData.created_at) {
  try {
    mttr_minutes = Math.max(0, (new Date(now).getTime() - new Date(incidentData.created_at).getTime()) / 60000);
    mttr_minutes = parseFloat(mttr_minutes.toFixed(2));
  } catch(e) {}
}

// Nettoyage store (court terme seulement)
if (incidentData.incident_id && incidentData.incident_id !== 'INC-UNKNOWN') {
  delete store[incidentData.incident_id];
}
delete store['LAST_INCIDENT'];
delete store['_last_contained_id'];

return [{ json: Object.assign({}, incidentData, {
  status        : 'CLOSED',
  etat_soar     : 'q6_Closed',
  closed_at     : now,
  firewall_rule : rule_id,
  mttr_minutes  : mttr_minutes,
  audit_trail   : trail
}) }];

