// ============================================================
// SOAR-002 — VT_Enrichissement
// CORRECTIONS :
//   1. Fallback complet si VT indisponible / quota / erreur
//   2. Suppression du fallback fragile $('Code_Triage_Incident')
//   3. Score VT critique → priorité P0 + flag store mis à jour
// ============================================================

var vtResponse = $input.first().json;
var now        = new Date().toISOString();
var store      = $getWorkflowStaticData('global');
var lastId     = store['LAST_INCIDENT'];

// ── LECTURE INCIDENT DEPUIS STORE ─────────────────────────
var incident = {};
if (lastId) {
  try { incident = JSON.parse(store[lastId] || '{}'); } catch(e) { incident = {}; }
}

if (!incident.incident_id) {
  console.log('[SOAR-002] WARN: VT_Enrichissement — incident introuvable en store pour ID: ' + lastId);
  incident = { incident_id: 'UNKNOWN', audit_trail: [], priority: 'P1', severity: 'HIGH', severity_score: 75 };
}

// ── DÉTECTION ÉCHEC VT ────────────────────────────────────
// Si VT est indisponible, le workflow NE DOIT PAS s'arrêter
// L'alerte analyste doit quand même partir
var vtFailed = !!(
  vtResponse.error          ||
  vtResponse.code           ||
  (vtResponse.statusCode && vtResponse.statusCode >= 400) ||
  !vtResponse.data
);

if (vtFailed) {
  console.log('[SOAR-002] WARN: VirusTotal indisponible ou quota dépassé — enrichissement ignoré, triage continue');

  var trailFail = Array.isArray(incident.audit_trail) ? incident.audit_trail : [];
  trailFail.push(now + ' | ENRICHMENT | VT_AUTO | INDISPONIBLE — triage sans enrichissement VT');

  // Mettre à jour le store avec le statut d'enrichissement partiel
  if (incident.incident_id && incident.incident_id !== 'UNKNOWN' && store[incident.incident_id]) {
    try {
      var storedFail        = JSON.parse(store[incident.incident_id]);
      storedFail.vt_verdict = 'UNAVAILABLE';
      storedFail.vt_error   = true;
      storedFail.etat_soar  = 'q2_Enrichissement_Partiel';
      storedFail.audit_trail = trailFail;
      store[incident.incident_id] = JSON.stringify(storedFail);
    } catch(e) {}
  }

  return [{ json: Object.assign({}, incident, {
    vt_score    : 0,
    vt_verdict  : 'UNAVAILABLE',
    vt_error    : true,
    vt_malicious: 0,
    vt_suspicious: 0,
    vt_total_av : 0,
    vt_country  : 'Unknown',
    vt_asn_owner: 'Unknown',
    audit_trail : trailFail,
    etat_soar   : 'q2_Enrichissement_Partiel'
  }) }];
}

// ── EXTRACTION RÉPONSE VT ─────────────────────────────────
var attrs     = vtResponse.data ? (vtResponse.data.attributes || {}) : {};
var stats     = attrs.last_analysis_stats || {};
var malicious = stats.malicious  || 0;
var suspicious= stats.suspicious || 0;
var harmless  = stats.harmless   || 0;
var total     = malicious + suspicious + harmless + (stats.undetected || 0);

var vtScore  = total > 0 ? Math.round(((malicious + suspicious) / total) * 100) : 0;
var country  = attrs.country  || 'Unknown';
var asOwner  = attrs.as_owner || 'Unknown';

var vtVerdict = 'UNKNOWN';
if (vtScore >= 50)      vtVerdict = 'MALICIOUS';
else if (vtScore >= 15) vtVerdict = 'SUSPICIOUS';
else if (total > 0)     vtVerdict = 'CLEAN';

// ── RÉÉVALUATION PRIORITÉ SELON VT ───────────────────────
var newPriority = incident.priority       || 'P1';
var newSeverity = incident.severity       || 'HIGH';
var newScore    = Number(incident.severity_score) || 75;

if (vtVerdict === 'MALICIOUS') {
  newPriority = 'P0';
  newSeverity = 'CRITICAL';
  newScore    = Math.min(100, newScore + 25);
} else if (vtVerdict === 'SUSPICIOUS') {
  // Suspicious : monter d'un cran mais pas forcément P0
  if (newPriority === 'P2' || newPriority === 'P3') newPriority = 'P1';
  if (newPriority === 'P1') newSeverity = 'HIGH';
  newScore = Math.min(100, newScore + 15);
}

var trail = Array.isArray(incident.audit_trail) ? incident.audit_trail : [];
trail.push(
  now +
  ' | ENRICHMENT | VT_AUTO | Score: ' + vtScore +
  '/100 — Verdict: ' + vtVerdict +
  ' — Country: ' + country +
  ' — ASN: ' + asOwner +
  ' — Detections: ' + malicious + '/' + total
);

// ── MISE À JOUR STORE ─────────────────────────────────────
if (incident.incident_id && incident.incident_id !== 'UNKNOWN' && store[incident.incident_id]) {
  try {
    var stored            = JSON.parse(store[incident.incident_id]);
    stored.priority       = newPriority;
    stored.severity       = newSeverity;
    stored.severity_score = newScore;
    stored.vt_score       = vtScore;
    stored.vt_verdict     = vtVerdict;
    stored.vt_country     = country;
    stored.vt_asn_owner   = asOwner;
    stored.audit_trail    = trail;
    stored.etat_soar      = 'q2_Enrichissement';
    store[incident.incident_id] = JSON.stringify(stored);
  } catch(e) {
    console.log('[SOAR-002] WARN: Impossible de mettre à jour le store VT pour: ' + incident.incident_id);
  }
}

return [{ json: Object.assign({}, incident, {
  vt_score      : vtScore,
  vt_malicious  : malicious,
  vt_suspicious : suspicious,
  vt_verdict    : vtVerdict,
  vt_country    : country,
  vt_asn_owner  : asOwner,
  vt_total_av   : total,
  priority      : newPriority,
  severity      : newSeverity,
  severity_score: newScore,
  audit_trail   : trail,
  etat_soar     : 'q2_Enrichissement'
}) }];

// AbuseIPDB Enrichissement
var abuseResponse = $input.first().json;
var store = $getWorkflowStaticData('global');
var lastId = store['LAST_INCIDENT'];
var incident = {};
if (lastId) {
  try { incident = JSON.parse(store[lastId] || '{}'); } catch(e) {}
}

var failed = !abuseResponse.data;
if (failed) {
  return [{ json: Object.assign({}, incident, {
    abuse_score  : 0,
    abuse_country: 'Unknown',
    abuse_isp    : 'Unknown',
    abuse_verdict: 'UNAVAILABLE'
  }) }];
}

var d = abuseResponse.data;
var score = d.abuseConfidenceScore || 0;
var verdict = score >= 75 ? 'MALICIOUS' : score >= 25 ? 'SUSPICIOUS' : 'CLEAN';

var trail = Array.isArray(incident.audit_trail) ? incident.audit_trail : [];
trail.push(new Date().toISOString() + ' | ENRICHMENT | ABUSEIPDB | Score: ' + score +
