var supabaseOtpUrl = String($vars.SUPABASE_OTP_URL || '').trim();
var otpEdgeToken   = String($vars.OTP_EDGE_TOKEN   || '').trim();

if (!supabaseOtpUrl || !otpEdgeToken) {
  // FALLBACK DÉGRADÉ : Math.random() multi-source si Edge Function non configurée
  // Acceptable pour développement/demo — PAS pour production
  console.log('[SOAR-002][WARN] SUPABASE_OTP_URL ou OTP_EDGE_TOKEN non configuré — fallback Math.random');

  var t1 = Date.now();
  var t2 = new Date().getMilliseconds();
  var r1 = Math.random();
  var r2 = Math.random();
  var r3 = Math.random();
  var r4 = Math.random();
  var r5 = Math.random();

  // Combinaison de 5 valeurs aléatoires + timestamp pour maximiser l'entropie
  var raw = Math.abs(
    Math.floor(t1 % 1000000 * r1) ^
    Math.floor(t2 * 997 * r2)     ^
    Math.floor(r3 * 0xFFFFFF)     ^
    Math.floor(r4 * 0xFFFFF)      ^
    Math.floor(r5 * 0xFFFFF + t1 % 100)
  );
  var otpFallback = String((raw % 900000) + 100000).substring(0, 6);
  if (!/^\d{6}$/.test(otpFallback)) otpFallback = String(100000 + Math.floor(Math.random() * 899999));

  var expiresFallback = new Date(Date.now() + 5 * 60 * 1000).toISOString();

  return [{ json: buildOutput(input, otpFallback, expiresFallback, now, true) }];
}

// Mode normal : préparer le payload pour HTTP_GenerateOTP (nœud suivant)
return [{ json: {
