// ============================================================
// SOAR-002 — Code_RetryLogic (NOUVEAU NŒUD)
// Retry avec backoff exponentiel, max 3 tentatives
// ============================================================

const store = $getWorkflowStaticData('global');
const input = $input.first().json;
const ts    = new Date().toISOString();

const retryKey = 'RETRY_' + (input.incident_id || 'unknown');
let retryState = {};
try { retryState = JSON.parse(store[retryKey] || '{}'); }
catch(e) { retryState = {}; }

const attempt  = (retryState.attempt || 0) + 1;
const MAX      = 3;
const delay_ms = 1000 * Math.pow(2, attempt - 1);
// Tentative 1 : 1s | Tentative 2 : 2s | Tentative 3 : 4s

console.log('[SOAR-002][RETRY] Tentative ' + attempt + '/' + MAX +
  ' — Incident: ' + (input.incident_id || 'unknown') +
  ' — Délai: ' + delay_ms + 'ms');

store[retryKey] = JSON.stringify({ attempt, ts: Date.now() });

if (attempt <= MAX) {
  return [{ json: {
    ...input,
    _retry_attempt: attempt,
    _retry_delay  : delay_ms,
    _should_retry : true,
    _dead_letter  : false,
    timestamp     : ts
  }}];
}

// Max atteint → dead-letter
delete store[retryKey];
console.log('[SOAR-002][DEAD-LETTER] Abandon après ' + MAX +
  ' tentatives — ' + (input.incident_id || 'unknown'));

return [{ json: {
  ...input,
  _retry_attempt: attempt,
  _should_retry : false,
  _dead_letter  : true,
  _error        : 'MAX_RETRIES_EXCEEDED — SIM-004 non joignable après 3 tentatives',
  timestamp     : ts
}}];

